public class Main {
    public static void main(String[] args) {
        int a = 5;  // binary: 0101
        int b = 3;  // binary: 0011

        System.out.println(a & b); // 0001 = 1
        System.out.println(a | b); // 0111 = 7
        System.out.println(a ^ b); // 0110 = 6
        System.out.println(a << 1); // 1010 = 10 (5 * 2)
        System.out.println(a >> 1); // 0010 = 2 (5 / 2, rounded down)
    }
}

public class Main {
    static boolean isBitSet(int num, int position) {
        return (num & (1 << position)) != 0;
    }

    static int setBit(int num, int position) {
        return num | (1 << position);
    }

    static int clearBit(int num, int position) {
        return num & ~(1 << position);
    }

    public static void main(String[] args) {
        int num = 5; // binary: 0101

        System.out.println(isBitSet(num, 0)); // bit 0 (value 1) -- is it set?
        System.out.println(isBitSet(num, 1)); // bit 1 (value 2) -- is it set?

        System.out.println(setBit(num, 1));   // set bit 1 -> 0111 = 7
        System.out.println(clearBit(num, 0)); // clear bit 0 -> 0100 = 4
    }
}

public class Main {
    static int findSingle(int[] nums) {
        int result = 0;
        for (int num : nums) {
            result ^= num;
        }
        return result;
    }

    public static void main(String[] args) {
        int[] nums = {4, 1, 2, 1, 2};
        System.out.println(findSingle(nums));
    }
}

